def assess(record: dict) -> str:
    required = {'spans', 'case_id', 'versions', 'trace_id', 'pii_in_trace'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get('trace_id') not in (None, False, 0, "", set(), [], {}):
        return 'PASS'
    return 'REJECT'

valid = {"case_id": 'CASO-SYN-1A', 'trace_id': True, 'spans': True, 'versions': True, 'pii_in_trace': True}
adverse = {"case_id": 'CASO-SYN-1A-ADV', 'trace_id': False, 'spans': False, 'versions': False, 'pii_in_trace': False}
missing = {k: valid[k] for k in valid if k != 'pii_in_trace'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

